# factorial.tcl

# Function to prompt the user for a positive integer and validate the input
proc get_positive_integer {prompt} {
    # Prompt the user for input
    puts $prompt
    set input [gets stdin]

    # Validate the input
    if {[string is integer -strict $input] && $input > 0} {
        return $input
    } else {
        # If the input is not a positive integer, re-prompt the user
        return -1
    }
}

# Recursive function to calculate the factorial of a number
proc factorial {n} {
    # Base case: factorial of 0 is 1
    if {$n == 0} {
        return 1
    } else {
        # Recursive case: n! = n * (n-1)!
        return [expr $n * [factorial [expr $n - 1]]]
    }
}

# Main procedure to run the script
proc main {} {
    # Get a positive integer from the user
    while {true} {
        set num [get_positive_integer "Enter a positive integer: "]
        if {$num != -1} {
            # Calculate the factorial
            set result [factorial $num]
            # Display the result
            puts "The factorial of $num is $result"
            break
        } else {
            puts "Invalid input. Please enter a positive integer."
        }
    }
}

# Call the main procedure to start the script
main
